UPDATE establishments SET address = REPLACE(address, 'Conceicao', 'Conceição') WHERE address LIKE '%Conceicao%' AND address NOT LIKE '%Conceição%';
UPDATE establishments SET address = REPLACE(address, 'Funchal', 'Funchal') WHERE 1=0;
